import{_ as e,o as h,c as p,a2 as t}from"./chunks/framework.Crpw6aS5.js";const _=JSON.parse('{"title":"伯克希尔哈撒韦 1973 年度报告","description":"","frontmatter":{},"headers":[],"relativePath":"01_letters/1973年/翻译.md","filePath":"01_letters/1973年/翻译.md"}'),r={name:"01_letters/1973年/翻译.md"};function o(l,a,m,i,n,s){return h(),p("div",null,[...a[0]||(a[0]=[t('<h1 id="伯克希尔哈撒韦-1973-年度报告" tabindex="-1"><a href="/03_companies/伯克希尔哈撒韦.html">伯克希尔哈撒韦</a> 1973 年度报告 <a class="header-anchor" href="#伯克希尔哈撒韦-1973-年度报告" aria-label="Permalink to &quot;[[伯克希尔哈撒韦]] 1973 年度报告&quot;">​</a></h1><h1 id="伯克希尔哈撒韦公司" tabindex="-1"><a href="/03_companies/伯克希尔哈撒韦.html">伯克希尔哈撒韦</a>公司 <a class="header-anchor" href="#伯克希尔哈撒韦公司" aria-label="Permalink to &quot;[[伯克希尔哈撒韦]]公司&quot;">​</a></h1><h1 id="_1973年致股东的年度报告" tabindex="-1">1973年致股东的年度报告 <a class="header-anchor" href="#_1973年致股东的年度报告" aria-label="Permalink to &quot;1973年致股东的年度报告&quot;">​</a></h1><p>（截至1973年12月29日，共52周）</p><h2 id="致伯克希尔哈撒韦公司全体股东" tabindex="-1">致<a href="/03_companies/伯克希尔哈撒韦.html">伯克希尔哈撒韦</a>公司全体股东： <a class="header-anchor" href="#致伯克希尔哈撒韦公司全体股东" aria-label="Permalink to &quot;致[[伯克希尔哈撒韦]]公司全体股东：&quot;">​</a></h2><p>1973年，公司财务表现稳健，营业收益达1193.0592万美元，对应期初股东权益回报率为17.4%。尽管每股营业收益从11.43美元提升至12.18美元，但股东权益回报率较1972年的19.8%有所下滑。下滑的核心原因是收益的增长幅度未能匹配股东投入资本的增幅。我们在去年的年报中已预测，回报率大概率会出现下滑。遗憾的是，这一预测成为了现实。</p><p>公司纺织、银行业务及保险板块的大部分业务线均实现了良好的年度表现，但保险业务的部分板块业绩不及预期。整体而言，保险业务仍是我们配置资本最具吸引力的领域。</p><p>管理层的长期目标是：在坚持稳健的会计政策与债务政策的前提下，实现长期平均资本回报率略高于美国工业企业的整体水平。过去几年，我们达成了这一目标；目前，我们正采取各项措施，力争在未来延续这一业绩表现。从1974年的经营前景来看，在持续扩大的权益基数下，公司回报率可能进一步下滑。</p><h3 id="纺织业务" tabindex="-1">纺织业务 <a class="header-anchor" href="#纺织业务" aria-label="Permalink to &quot;纺织业务&quot;">​</a></h3><p>1973年全年，纺织品市场需求持续保持异常旺盛的态势。我们面临的核心问题集中于纤维原料短缺，这不仅打乱了生产经营节奏，还导致织机产能未能完全释放。年内，部分纤维原料价格出现暴涨。</p><p>美国生活成本委员会的价格管制规定，使得我们诸多成品的定价无法达到部分竞争对手的水平。尽管如此，业务利润与我们的资本投入仍基本匹配，只是低于若能按市场水平定价可实现的收益水平。纺织行业具有极强的周期性，价格管制或许削平了行业上行期的盈利峰值，却无法避免行业下行期必然到来的利润低谷。</p><p>1973年，原材料价格出现异常上涨，且1974年仍有持续迹象。基于此，我们决定采用<strong>后进先出法（LIFO）</strong> 进行存货计价。该方法能更精准地将当期成本与当期收入进行配比，同时最大限度降低报告收益中包含的存货&quot;账面利润&quot;。本次会计政策变更的详细信息，详见财务报表附注。</p><h3 id="保险业务" tabindex="-1">保险业务 <a class="header-anchor" href="#保险业务" aria-label="Permalink to &quot;保险业务&quot;">​</a></h3><p>1973年，杰克·林沃尔特先生卸任国民赔偿公司总裁一职。他于1940年创立该公司，任职期间创下了极为辉煌的经营纪录。菲尔·利舍先生接任总裁一职，对我们而言十分幸运的是，他始终秉持着杰克先生行之有效的承保与管理理念。</p><p>我们的传统核心业务——通过国民赔偿公司、国民火灾与海上保险公司开展的特种汽车保险与一般责任险业务，在1973年实现了极为出色的承保业绩。年内，我们的业务规模再次出现下滑。当时市场竞争异常激烈，众多承保机构对风险持更为乐观的态度，纷纷下调费率，而我们并未跟风降价。目前已有微弱迹象表明，部分竞争对手已意识到其费率水平（以及损失准备金）存在严重不足，这可能会在年内逐步缓解市场的恶性竞争压力。若该情况出现，我们的业务规模有望重回增长。</p><p>我们的再保险业务全年表现与传统业务较为相似：承保端表现良好，但难以维持此前的业务规模。该业务自1969年成立以来，在乔治·杨先生孜孜不倦、方向精准的管理下，已成为公司核心的利润来源之一。</p><p>我们的&quot;本土州&quot;保险公司在内布拉斯加州与明尼苏达州取得了优异进展，既实现了业务规模的稳健增长，也保持了合理的赔付率。年内晚些时候，我们在爱荷华州正式开展业务。截至目前，该板块最大的难题出现在得克萨斯州。1973年，由于最初选定的管理团队不具备成功的承保能力，我们在该州几乎不得不推倒重来。得克萨斯州的业务拓展让我们付出了高昂的代价，且相关整改工作仍未完成。但整体来看，本土州业务仍具备可观的发展潜力。</p><p>我们的特种城市汽车保险运营主体——家庭与汽车保险公司，1973年在芝加哥地区的承保业绩极差。尽管当前的能源危机让市场前景变得复杂，但我们核心的库克县营销区域的费率水平显然存在不足。核心问题在于：驾驶里程减少可能带来的事故发生率下降，能否抵消医疗、车辆维修成本以及陪审团判决赔偿金额持续通胀带来的影响。我们认为，通胀带来的负面影响，将远超驾驶减少带来的利好，但部分竞争对手似乎持相反观点。</p><p>年内，家庭与汽车保险公司将业务拓展至佛罗里达州与加利福尼亚州，不过目前判断这些举措的财务回报仍为时尚早。</p><p>1973年，家庭与汽车保险公司收益不及预期的另一重要原因，是其会计系统无法及时向管理层传递经营数据。目前，这一问题已在整改中。</p><p>在保险业务的投资端，我们在1973年对普通股进行了大规模的增持。如财务报表所示，截至年末，我们持有的普通股组合出现了超过1200万美元的巨额未实现贬值。尽管如此，我们认为，按成本价计量的普通股组合，从企业内在价值来看具备良好的投资价值。即便年末存在大额未实现亏损，我们仍预计该组合长期将带来稳健的收益。</p><h3 id="银行业务" tabindex="-1">银行业务 <a class="header-anchor" href="#银行业务" aria-label="Permalink to &quot;银行业务&quot;">​</a></h3><p>罗克福德伊利诺伊国民银行信托公司在1973年再次创下业绩新高。年内平均存款规模约1.3亿美元，其中约60%为定期存款。年中监管机构上调存款利率上限后，我们大幅上调了核心居民储蓄存款的利率水平。</p><p>尽管存款结构中付息存款占比极高，但税后营业收益（含伊利诺伊州新开征的州所得税）仍再次超过平均存款规模的2.1%。</p><p>我们仍是罗克福德地区规模最大的银行，始终保持着极高的流动性水平，持续满足客户不断增长的贷款需求，同时维持着行业罕见的盈利能力。这一切都要归功于自1931年银行成立以来便执掌经营的董事长<a href="/04_people/吉恩·阿贝格.html">吉恩·阿贝格</a>先生，以及总裁鲍勃·克莱因先生的卓越能力。</p><h3 id="与多元零售公司的合并事宜" tabindex="-1">与多元零售公司的合并事宜 <a class="header-anchor" href="#与多元零售公司的合并事宜" aria-label="Permalink to &quot;与多元零售公司的合并事宜&quot;">​</a></h3><p>公司董事会已批准多元零售公司并入<a href="/03_companies/伯克希尔哈撒韦.html">伯克希尔哈撒韦</a>公司的合并方案，交易对价为：发行19.5万股<a href="/03_companies/伯克希尔哈撒韦.html">伯克希尔哈撒韦</a>股票，兑换多元零售公司发行在外的100万股普通股。由于多元零售公司及其子公司已持有109551股<a href="/03_companies/伯克希尔哈撒韦.html">伯克希尔哈撒韦</a>股票，交易完成后，<a href="/03_companies/伯克希尔哈撒韦.html">伯克希尔哈撒韦</a>发行在外的股份净增幅不超过85449股。本次合并需取得多项监管审批，相关委托投票材料将于今年晚些时候向各位股东提交，供股东投票表决。</p><p>多元零售公司通过旗下子公司，运营着平价女装连锁门店，同时开展再保险业务。在公司管理层看来，其最重要的资产是持有的<a href="/03_companies/蓝筹印花.html">蓝筹印花</a>公司16%的股权。</p><h3 id="蓝筹印花公司" tabindex="-1"><a href="/03_companies/蓝筹印花.html">蓝筹印花</a>公司 <a class="header-anchor" href="#蓝筹印花公司" aria-label="Permalink to &quot;[[蓝筹印花]]公司&quot;">​</a></h3><p>截至年末，我们持有的<a href="/03_companies/蓝筹印花.html">蓝筹印花</a>公司股权，约占该公司发行在外股份的19%。年末之后，我们进一步增持，目前持股比例已升至约22.5%；若与多元零售公司的合并方案落地，我们的持股比例将进一步提升至约38.5%。</p><p>1973年，我们在<a href="/03_companies/蓝筹印花.html">蓝筹印花</a>公司的收益权益首次达到重要规模，这也带来了一个会计问题：<a href="/03_companies/伯克希尔哈撒韦.html">伯克希尔哈撒韦</a>公司在本年报对应的财务报表中，应确认该公司哪一期间的收益。</p><p><a href="/03_companies/蓝筹印花.html">蓝筹印花</a>公司的财年截止日为每年2月28日最近的周六，较<a href="/03_companies/伯克希尔哈撒韦.html">伯克希尔哈撒韦</a>的财年截止日晚2个月；换个角度看，其财年结束时间较<a href="/03_companies/伯克希尔哈撒韦.html">伯克希尔哈撒韦</a>的财年提前10个月。我们本可以选择一种合规的会计处理方式（且无需审计师出具审计范围受限的免责声明）：在1973年的收益中，确认我们在<a href="/03_companies/蓝筹印花.html">蓝筹印花</a>公司1973年3月3日结束的财年中对应的63.2万美元收益权益（对应我们在该较早期间持有的较低股份规模）。但这种处理方式与实际经营情况不符，且意味着未来每年的收益确认都将存在10个月的滞后。因此，我们选择在1973年的收益中，确认100.8万美元的<a href="/03_companies/蓝筹印花.html">蓝筹印花</a>公司收益权益——该数据基于<a href="/03_companies/蓝筹印花.html">蓝筹印花</a>公司公开披露的截至11月的未经审计中期业绩，以及我们1973年全年的持股情况。</p><p>由于我们选择了未经审计但贴合当期的经营数据，而非经审计但严重滞后的历史数据，毕马威会计师事务所无法对我们1973年收益中归属于<a href="/03_companies/蓝筹印花.html">蓝筹印花</a>公司的部分发表审计意见。</p><p><a href="/03_companies/蓝筹印花.html">蓝筹印花</a>公司的年度报告（含普华永道会计师事务所审计的截至1974年3月2日财年的财务报表）将于5月初发布。<a href="/03_companies/伯克希尔哈撒韦.html">伯克希尔哈撒韦</a>的任何股东若需获取该报告，可届时致信加州洛杉矶市东南大道5801号，<a href="/03_companies/蓝筹印花.html">蓝筹印花</a>公司董事会秘书罗伯特·H·伯德先生（邮编90040）索取。</p><p>过去一年左右，<a href="/03_companies/蓝筹印花.html">蓝筹印花</a>公司的交易印花业务出现大幅下滑，但其旗下的<a href="/03_companies/喜诗糖果.html">喜诗糖果</a>店子公司，以及持股54%、主营储贷业务的韦斯科金融公司，均具备重要的盈利能力来源。我们预计，未来<a href="/03_companies/蓝筹印花.html">蓝筹印花</a>公司将实现与投入资本相匹配的稳健收益，尽管其收益水平必然远低于交易印花业务维持在历史高位时可实现的规模。</p><p>本公司董事长担任<a href="/03_companies/蓝筹印花.html">蓝筹印花</a>公司、韦斯科金融公司的董事，同时担任<a href="/03_companies/喜诗糖果.html">喜诗糖果</a>公司的董事会主席。这三家主体的经营管理均由一流，专业、经验丰富的管理团队负责。</p><h3 id="太阳报业公司" tabindex="-1">太阳报业公司 <a class="header-anchor" href="#太阳报业公司" aria-label="Permalink to &quot;太阳报业公司&quot;">​</a></h3><p>在1969年的年报中，我们曾提及收购了太阳报业公司——一家在奥马哈<a href="/03_companies/大都会.html">大都会</a>区发行多份周报的报业机构。此后，我们从未在年报正文中提及该公司的经营情况，也未合并其财务报表，因为这笔投资规模较小，在财务上&quot;无足轻重&quot;。</p><p>但1973年发生的事清晰地证明，这种&quot;无足轻重&quot;从未延伸至出版品质层面。1973年5月7日，太阳报业凭借1972年3月30日发布的关于男孩镇的特别报道，荣获普利策本地调查报道奖——这是历史上首次有周报机构斩获该类别奖项。我们在报道中揭露了自1948年弗拉纳根神父去世后，男孩镇服务持续缩减、财富却不断累积的惊人反差。</p><p>除普利策奖外，这篇调查报道还斩获了美国职业记者协会西格玛德尔塔奇公共服务奖，以及其他7项全国性奖项。</p><p>我们向主编保罗·威廉姆斯、发行人<a href="/04_people/斯坦·利普西.html">斯坦·利普西</a>，以及太阳报业的全体编辑团队致以祝贺。他们的成就生动地证明：在出版行业，规模大小与价值分量从来都不能划等号。</p><p>沃伦·E·<a href="/04_people/沃伦·巴菲特.html">沃伦·巴菲特</a></p><p>董事会主席</p><p>1974年3月29日</p><hr><p><em>完整财务报表详见原始年报</em></p>',46)])])}const f=e(r,[["render",o]]);export{_ as __pageData,f as default};
